func (e customErr) ErrorType() string { return string(e) }

type customWrap struct{ err error }
func (e customWrap) Error() string { return "custom wrap: " + e.err.Error() }
func (e customWrap) Unwrap() error { return e.err }

func main() {
        checks := []struct{
                name string
                err error
                want string
        }{
                {"unwrapped concrete", baseErr{}, "main.baseErr"},
                {"single fmt wrap", fmt.Errorf("context: %w", baseErr{}), "main.baseErr"},
                {"nested fmt wrap", fmt.Errorf("outer: %w", fmt.Errorf("inner: %w", baseErr{})), "main.baseErr"},
                {"fmt wrap errors.New", fmt.Errorf("context: %w", errors.New("boom")), "*errors.errorString"},
                {"fmt wrap custom ErrorType", fmt.Errorf("context: %w", customErr("aborted")), "aborted"},
                {"custom wrapper preserved", customWrap{err: baseErr{}}, "main.customWrap"},
                {"fmt then custom wrapper", fmt.Errorf("context: %w", customWrap{err: baseErr{}}), "main.customWrap"},
        }
        failed := false
        for _, c := range checks {
                got := semconv.ErrorType(c.err).Value.AsString()
                fmt.Printf("%s: got %q, want %q\n", c.name, got, c.want)
                if got != c.want {
                        failed = true
                }
        }
        if failed {
                os.Exit(1)
        }
}
